sys_script.script:
(function executeRule(current, previous) {

    var notes = (current.session_notes + '').toLowerCase();

    var summary = 'General counseling session completed.';
    var recommendation = 'Monitor student progress.';

    if (
        notes.indexOf('stress') > -1 ||
        notes.indexOf('exam') > -1 ||
        notes.indexOf('placement') > -1 ||
        notes.indexOf('pressure') > -1
    ) {

        summary = 'Student is experiencing academic stress and performance pressure.';
        recommendation = 'Schedule counselor follow-up within 7 days.';
    }

    else if (
        notes.indexOf('anxiety') > -1 ||
        notes.indexOf('panic') > -1 ||
        notes.indexOf('worried') > -1
    ) {

        summary = 'Student shows signs of anxiety.';
        recommendation = 'Provide emotional support resources.';
    }

    else if (
        notes.indexOf('improved') > -1 ||
        notes.indexOf('better') > -1 ||
        notes.indexOf('progress') > -1
    ) {

        summary = 'Student is showing positive progress.';
        recommendation = 'Continue current counseling plan.';
    }

    current.ai_session_summary = summary;
    current.follow_up_recommendation = recommendation;
    current.ai_summary_generated = true;

})(current, previous);
